Here is a simple C++ function that uses the `std::regex` and `std::string` libraries to convert markdown to html. This function will convert the following markdown syntax to html:

* Headers: `# Heading` -> `<h1>Heading</h1>`
* Bold text: `**Bold text**` -> `<b>Bold text</b>`
* Italic text: `*Italic text*` -> `<i>Italic text</i>`
* Links: `[Link text](http://www.example.com)` -> `<a href="http://www.example.com">Link text</a>`
* Lists: `- Item 1`, `- Item 2` -> `<ul><li>Item 1</li><li>Item 2</li></ul>`
* Code blocks: ````Code```` -> ````<pre><code>Code</code></pre>````

```cpp
#include <regex>
#include <string>
#include <iostream>

std::string markdownToHtml(const std::string& markdown) {
    std::string html;
    std::regex regexHeader("^# (.*)$", std::regex::ECMAScript);
    std::regex regexBold("^(\\*|__)\\s(.*)\\1$");
    std::regex regexItalic("^(\\*|_)\\s(.*)\\1$");
    std::regex regexLink("\\[(.*)\\]\\((.*)\\)");
    std::regex regexList("^(\\s*-\\s(.*)$");
    std::regex regexCodeBlock("^```(.*)```$");

    std::smatch match;
    std::string temp;

    // Headers
    while (std::regex_search(markdown, match, regexHeader)) {
        html += "<h1>" + match[1] + "</h1>";
        markdown = match.suffix().str();
    }

    // Bold text
    while (std::regex_search(markdown, match, regexBold)) {
        html += "<b>" + match[2] + "</b>";
        markdown = match.suffix().str();
    }

    // Italic text
    while (std::regex_search(markdown, match, regexItalic)) {
        html += "<i>" + match[2] + "</i>";
        markdown = match.suffix().str();
    }

    // Links
    while (std::regex_search(markdown, match, regexLink)) {
        html += "<a href=\"" + match[2] + "\">" + match[1] + "</a>";
        markdown = match.suffix().str();
    }

    // Lists
    while (std::regex_search(markdown, match, regexList)) {
        html += "<ul><li>" + match[2] + "</li></ul>";
        markdown = match.suffix().str();
    }

    // Code blocks
    while (std::regex_search(markdown, match, regexCodeBlock)) {
        html += "<pre><code>" + match[1] + "</code></pre>";
        markdown = match.suffix().str();
    }

    return html;
}

int main() {
    std::string markdown = "# Hello World\n"
                           "**Bold text**\n"
                           "*Italic text*\n"
                           "[Link text](http://www.example.com)\n"
                           "- Item 1\n"
                           "- Item 2\n"
                           "````Code````";
    std::string html = markdownToHtml(markdown);
    std::cout << html << std::endl;
    return 0;
}
```

